// Localiza o primeiro binário .xlsx/.xls/.csv recebido pelo Webhook.
// O n8n nomeia arquivos multipart como data0, data1, ... (com binaryPropertyName=data).
// Renomeia para 'data0' para alimentar o nó Update File com nome estável.
const item = $input.first();
const bin = item.binary || {};
const keys = Object.keys(bin);

if (keys.length === 0) {
  throw new Error('Nenhum arquivo recebido. Envie um .xlsx no campo do form-data.');
}

// Pega o primeiro binário (data0 normalmente).
const sourceKey = keys[0];
const fileBin = bin[sourceKey];
const fileName = (fileBin.fileName || '').toLowerCase();
const mime = (fileBin.mimeType || '').toLowerCase();

const valid = fileName.endsWith('.xlsx') || fileName.endsWith('.xls') || fileName.endsWith('.csv')
  || mime.includes('spreadsheetml') || mime.includes('excel') || mime.includes('csv');

if (!valid) {
  throw new Error(`Arquivo inválido: ${fileBin.fileName || sourceKey}. Envie .xlsx, .xls ou .csv.`);
}

// Campos de texto do form-data (mês de referência), se enviados pelo front.
const body = item.json && item.json.body ? item.json.body : (item.json || {});
const periodo = body.periodo || null;  // YYYY-MM
const rotulo = body.rotulo || null;    // ex.: 'Junho/2026'

return [{
  json: {
    received_file: fileBin.fileName,
    mime: fileBin.mimeType,
    size_bytes: fileBin.fileSize || null,
    periodo,
    rotulo
  },
  binary: { data0: fileBin }
}];

// O sub-fluxo retorna o SUMARIO_PRE_CALCULADO como primeiro item.
// Localiza o objeto que contém produtos[] (independente do wrapper).
let sumario = null;
for (const it of $input.all()) {
  const j = it.json || {};
  // GUARDA: se o sub-fluxo devolveu a LISTA DE ABAS, a aba configurada não existe.
  // Falha com mensagem clara em vez de capturar vazio silenciosamente.
  if (Array.isArray(j.abas_disponiveis)) {
    throw new Error('Sub-fluxo retornou a lista de abas em vez dos dados. A aba configurada em "Obter Sumário" (nome_do_separador) não existe na planilha. Abas disponíveis: ' + j.abas_disponiveis.join(', ') + '. Ajuste o parametro nome_do_separador para uma destas.');
  }
  if (Array.isArray(j.produtos)) { sumario = j; break; }
  if (j.__tipo === 'SUMARIO_PRE_CALCULADO' && Array.isArray(j.produtos)) { sumario = j; break; }
  if (j.json && Array.isArray(j.json.produtos)) { sumario = j.json; break; }
}

if (!sumario || !Array.isArray(sumario.produtos)) {
  // Não bloqueia o upload: apenas sinaliza que não houve captura.
  return [{ json: { _capturar: false, motivo: 'SUMARIO_PRE_CALCULADO sem produtos[]' } }];
}

const meta = $('Validar Arquivo').first().json;
const fileName = meta.received_file || null;
return [{
  json: {
    _capturar: true,
    produtos: sumario.produtos,
    arquivo_nome: fileName,
    periodo: meta.periodo || null,
    rotulo: meta.rotulo || null,
    user_id: null
  }
}];
